class Solution:
    def maxOperations(self, s: str) -> int:
        operations = 0
        n = len(s)
        i = 0
        while i < n - 1:
            if s[i] == '1' and s[i + 1] == '0':
                # Move the '1' to the right as far as possible
                j = i
                while j < n - 1 and s[j + 1] == '0':
                    j += 1
                # Move the '1' to position j
                s = s[:i] + '0' + s[i + 1:j + 1] + '1' + s[j + 1:]
                operations += 1
                i = 0  # Reset index to start from the beginning again
            else:
                i += 1
        return operations
